module RefModule (  
    input wire [3:0] data_in,  
    output reg [3:0] data_out,  
    input wire we,  
    input wire clk  
);  
    reg [3:0] memory;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (we)  
            memory <= data_in;  
    end  

    always @(*) begin  
        data_out = memory;  
    end  
endmodule
